package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.RoomServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/rooms/create")public class RoomCreateServlet extends HttpServlet{protected final RoomService s=new RoomServiceImpl();protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setAttribute("roomForm",new RoomForm());show(q,r,"CREATE");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{RoomForm f=form(q);ServiceResult<Long>x=s.createRoom(f,AdmissionRequest.audit(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/rooms/view?id="+x.getData());return;}q.setAttribute("roomForm",f);q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,"CREATE");}protected RoomForm form(HttpServletRequest q){RoomForm f=new RoomForm();f.setRoomId(AdmissionRequest.id(q.getParameter("roomId")));f.setRoomNumber(q.getParameter("roomNumber"));f.setRoomType(q.getParameter("roomType"));f.setFloorNumber(q.getParameter("floorNumber"));f.setDepartmentId(AdmissionRequest.id(q.getParameter("departmentId")));f.setDailyRate(q.getParameter("dailyRate"));f.setStatus(q.getParameter("status"));return f;}protected void show(HttpServletRequest q,HttpServletResponse r,String m)throws ServletException,IOException{q.setAttribute("formMode",m);q.getRequestDispatcher("/WEB-INF/views/admin/rooms/form.jsp").forward(q,r);}}
